package com.app.features.dashboard.data

import com.app.features.dashboard.model.Survey
import com.app.features.dashboard.model.SurveyStatus

object SurveyRepository {
    fun getAllSurveys(): List<Survey> = MOCK_SURVEYS.toList()

    fun getSurveyById(id: Int): Survey? = MOCK_SURVEYS.find { it.id == id }

    fun updateSurveyStatus(id: Int, status: SurveyStatus): Boolean {
        val survey = MOCK_SURVEYS.find { it.id == id }
        return if (survey != null) {
            val index = MOCK_SURVEYS.indexOf(survey)
            MOCK_SURVEYS[index] = survey.copy(status = status)
            true
        } else false
    }
}

